package server

import (
	"strconv"

	"github.com/agurrrrr/shepherd/ent"
	"github.com/agurrrrr/shepherd/internal/wiki"
	"github.com/gofiber/fiber/v2"
)

// wikiPageToMap converts an ent.WikiPage to a fiber.Map for JSON response.
func wikiPageToMap(p *ent.WikiPage) fiber.Map {
	m := fiber.Map{
		"id":             p.ID,
		"slug":           p.Slug,
		"title":          p.Title,
		"content":        p.Content,
		"category":       p.Category,
		"auto_generated": p.AutoGenerated,
		"tags":           p.Tags,
		"created_at":     p.CreatedAt,
		"updated_at":     p.UpdatedAt,
	}
	if !p.LastUpdatedByTask.IsZero() {
		m["last_updated_by_task"] = p.LastUpdatedByTask
	}
	return m
}

// GET /api/wiki/pages — list wiki pages for a project
func (s *Server) handleListWikiPages(c *fiber.Ctx) error {
	projectName := c.Query("project")
	if projectName == "" {
		return fail(c, fiber.StatusBadRequest, "project query parameter is required")
	}

	pages, err := wiki.ListPages(projectName)
	if err != nil {
		return fail(c, fiber.StatusInternalServerError, err.Error())
	}

	var items []fiber.Map
	for _, p := range pages {
		items = append(items, wikiPageToMap(p))
	}
	if items == nil {
		items = []fiber.Map{}
	}

	return success(c, items)
}

// GET /api/wiki/pages/:slug — get a specific wiki page
func (s *Server) handleGetWikiPage(c *fiber.Ctx) error {
	projectName := c.Query("project")
	if projectName == "" {
		return fail(c, fiber.StatusBadRequest, "project query parameter is required")
	}

	slug := c.Params("slug")

	page, err := wiki.GetPage(projectName, slug)
	if err != nil {
		return fail(c, fiber.StatusNotFound, err.Error())
	}

	return success(c, wikiPageToMap(page))
}

// POST /api/wiki/pages — create a wiki page
func (s *Server) handleCreateWikiPage(c *fiber.Ctx) error {
	var body struct {
		ProjectName string   `json:"projectName"`
		Slug        string   `json:"slug"`
		Title       string   `json:"title"`
		Category    string   `json:"category"`
		Content     string   `json:"content"`
		Tags        []string `json:"tags"`
	}
	if err := c.BodyParser(&body); err != nil {
		return fail(c, fiber.StatusBadRequest, "invalid request body")
	}

	if body.ProjectName == "" {
		return fail(c, fiber.StatusBadRequest, "projectName is required")
	}
	if body.Slug == "" {
		return fail(c, fiber.StatusBadRequest, "slug is required")
	}
	if body.Title == "" {
		return fail(c, fiber.StatusBadRequest, "title is required")
	}

	page, err := wiki.CreatePage(body.ProjectName, body.Slug, body.Title, body.Category, body.Content, body.Tags)
	if err != nil {
		return fail(c, fiber.StatusBadRequest, err.Error())
	}

	return success(c, wikiPageToMap(page))
}

// PUT /api/wiki/pages/:slug — update a wiki page
func (s *Server) handleUpdateWikiPage(c *fiber.Ctx) error {
	projectName := c.Query("project")
	if projectName == "" {
		return fail(c, fiber.StatusBadRequest, "project query parameter is required")
	}

	slug := c.Params("slug")

	var body struct {
		Title   string   `json:"title"`
		Content string   `json:"content"`
		Tags    []string `json:"tags"`
	}
	if err := c.BodyParser(&body); err != nil {
		return fail(c, fiber.StatusBadRequest, "invalid request body")
	}

	page, err := wiki.UpdatePage(projectName, slug, body.Title, body.Content, body.Tags)
	if err != nil {
		return fail(c, fiber.StatusBadRequest, err.Error())
	}

	return success(c, wikiPageToMap(page))
}

// DELETE /api/wiki/pages/:slug — delete a wiki page
func (s *Server) handleDeleteWikiPage(c *fiber.Ctx) error {
	projectName := c.Query("project")
	if projectName == "" {
		return fail(c, fiber.StatusBadRequest, "project query parameter is required")
	}

	slug := c.Params("slug")

	if err := wiki.DeletePage(projectName, slug); err != nil {
		return fail(c, fiber.StatusNotFound, err.Error())
	}

	return success(c, fiber.Map{"deleted": true})
}

// POST /api/wiki/lint — run lint on wiki pages
func (s *Server) handleWikiLint(c *fiber.Ctx) error {
	projectName := c.Query("project")
	if projectName == "" {
		return fail(c, fiber.StatusBadRequest, "project query parameter is required")
	}

	issues := wiki.Lint(projectName)
	if issues == nil {
		issues = []wiki.WikiIssue{}
	}

	var items []fiber.Map
	for _, issue := range issues {
		items = append(items, fiber.Map{
			"type":    issue.Type,
			"slug":    issue.Slug,
			"message": issue.Message,
		})
	}

	return success(c, fiber.Map{
		"issues":  items,
		"count":   len(items),
		"project": projectName,
	})
}

// GET /api/wiki/pages/:slug/versions — get version history for a wiki page
func (s *Server) handleWikiPageVersions(c *fiber.Ctx) error {
	projectName := c.Query("project")
	if projectName == "" {
		return fail(c, fiber.StatusBadRequest, "project query parameter is required")
	}

	slug := c.Params("slug")

	versions, err := wiki.PageVersionHistory(projectName, slug)
	if err != nil {
		return fail(c, fiber.StatusInternalServerError, err.Error())
	}

	var items []fiber.Map
	for _, v := range versions {
		items = append(items, fiber.Map{
			"id":         v.ID,
			"page_slug":  v.PageSlug,
			"content":    v.Content,
			"summary":    v.Summary,
			"author":     v.Author,
			"created_at": v.CreatedAt,
		})
	}
	if items == nil {
		items = []fiber.Map{}
	}

	return success(c, items)
}

// POST /api/wiki/ingest/:task_id — stub for manual ingest re-execution
func (s *Server) handleWikiIngest(c *fiber.Ctx) error {
	taskIDStr := c.Params("task_id")
	taskID, err := strconv.Atoi(taskIDStr)
	if err != nil {
		return fail(c, fiber.StatusBadRequest, "invalid task ID")
	}

	_ = taskID

	return success(c, fiber.Map{
		"message": "ingest stub — actual logic will be implemented in a later step",
		"task_id": taskID,
	})
}
